const items = $input.all();
const first = items[0]?.json || {};

// After Merge multiplex, first item has both datasets merged
// But we need to get stats and bookings separately
const statsData = $('RPC → get_daily_stats').first().json;
const bookingsData = $('REST → Yesterday Bookings').all().map(i => i.json);

const combined = {
  aggregated_stats: statsData,
  yesterday_bookings: Array.isArray(bookingsData) ? bookingsData : [],
  bookings_count: Array.isArray(bookingsData) ? bookingsData.length : 0,
  date: new Date().toISOString().split('T')[0]
};

return [{ json: combined }];

try {
  const raw = $input.first().json.content[0].text;
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const digest = JSON.parse(cleaned);
  return [{ json: {
    status: 'completed',
    workflow: '08_daily_digest',
    date: new Date().toISOString().split('T')[0],
    yesterday_date: new Date(Date.now() - 86400000).toISOString().split('T')[0],
    digest,
    completedAt: new Date().toISOString()
  } }];
} catch (e) {
  const raw = $input.first().json.content?.[0]?.text || 'No content';
  return [{ json: {
    status: 'completed',
    workflow: '08_daily_digest',
    content_raw: raw,
    parse_note: 'Response was not valid JSON, returning raw text',
    completedAt: new Date().toISOString()
  } }];
}
